/**
 * Function: Test transactional observer updates
 *
 * @param nodeName Name for the node to update
 * @return bool Whether transactional update succeeded (no cycle created)
 */
bool test_transactional_update(const std::string& nodeName) {
    // 1. Create two observer nodes: source and target
    auto source = std::make_shared<TestTransactionalObserver>(nodeName);
    auto target = std::make_shared<TestTransactionalObserver>("target_node");

    // 2. Get the observer graph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Set up initial relationship (source observes target)
    observerGraph.addObserver(source, target);

    // 4. Notify target and verify relationship works
    target->valueChanged(true);

    // Verify source was notified
    if (!source->wasChanged()) {
        return false; // Relationship verification failed
    }

    // 5. Reset observer for next test
    source->reset();
    target->reset();
    observerGraph.resetForTesting();

    // 6. Attempt transactional update that would create cycle
    bool success = false;

    try {
        // Attempt to create cycle: target observes source
        observerGraph.addObserver(target, source);

        // If we reach here, no exception was thrown - cycle was created
        success = false;
    }
    catch (const reaction::CycleException& e) {
        // 7. Cycle exception caught - transactional update prevented cycle

        // 8. Notify target again to verify original relationship preserved
        target->valueChanged(true);

        // 9. Verify original relationship is preserved
        if (source->wasChanged()) {
            // Original relationship still working after transactional update
            success = true;
        } else {
            success = false;
        }
    }
    catch (...) {
        // Other exceptions indicate test failure
        success = false;
    }

    // 10. Return success status
    return success;
}

