    auto owner = std::make_shared<FieldOwnerNode>();

    auto &graph = ObserverGraph::getInstance();
    graph.addNode(owner);

    FieldGraph::getInstance().bindField(fields.getId(), owner);

    fields.score().value(initialScore + scoreDelta);
