#pragma once

#include <reaction/reaction.h>
#include <cstdint>

namespace test_reaction {

struct AtomicCompoundSnapshot {
    int afterAddition;
    int afterMultiplication;
    int afterBitwiseAnd;
    int afterShift;
    int postIncrementReturn;
    int finalValue;
    int calcEvaluations;
};

/**
 * Function: Demonstrate atomic compound assignments on a reactive counter.
 *
 * @return AtomicCompoundSnapshot Snapshot with values after each compound operation.
 */
inline AtomicCompoundSnapshot test_atomic_compound_assign() {
    using namespace reaction;

    // 1. Create reactive variable with initial value 0
    auto counter = var(0);

    // 2. Create counter for calculation evaluations with initial value 0
    auto calcCounter = var(0);

    // 3. Create calculation that increments calcCounter and returns current counter value
    auto calc = calc([&]() {
        calcCounter += 1;  // Increment evaluation counter
        return counter.get();
    });

    // 4. Use operator+= to add 5 to the counter
    counter += 5;

    // 5. Use get() to get value after addition
    int afterAddition = counter.get();

    // 6. Use operator*= to multiply the counter by 2
    counter *= 2;

    // 7. Use get() to get value after multiplication
    int afterMultiplication = counter.get();

    // 8. Use operator&= to apply bitwise AND with 3
    counter &= 3;

    // 9. Use get() to get value after bitwise AND
    int afterBitwiseAnd = counter.get();

    // 10. Use operator<<= to left shift by 1
    counter <<= 1;

    // 11. Use get() to get value after shift
    int afterShift = counter.get();

    // 12. Use post-increment operator ++ (counter++)
    int postIncrementReturn = counter++;

    // 13. Use get() to get final value
    int finalValue = counter.get();

    // 14. Get calculation evaluations count from calcCounter
    int calcEvaluations = calcCounter.get();

    // 15. Return the filled snapshot
    return AtomicCompoundSnapshot{
        .afterAddition = afterAddition,
        .afterMultiplication = afterMultiplication,
        .afterBitwiseAnd = afterBitwiseAnd,
        .afterShift = afterShift,
        .postIncrementReturn = postIncrementReturn,
        .finalValue = finalValue,
        .calcEvaluations = calcEvaluations
    };
}

}  // namespace test_reaction
```

## Key Implementation Details:

1. **Reactive Variable Creation**: Used `reaction::var(0)` to create reactive variables with initial value 0
2. **Calculation Creation**: Used `reaction::calc()` with a lambda that increments the evaluation counter and returns the current counter value
3. **Atomic Operations**: Used all required compound assignment operators (`+=`, `*=`, `&=`, `<<=`) as specified
4. **Value Retrieval**: Used `get()` method to retrieve values after each operation
5. **Post-increment**: Used the post-increment operator `counter++` which returns the old value
6. **Evaluation Tracking**: The calculation automatically tracks evaluations through the `calcCounter` variable
7. **Snapshot Return**: Returns a properly populated `AtomicCompoundSnapshot` struct

This implementation follows all the assessment objectives and correctly uses the `reaction` library functions as specified in the reference materials.

