```cpp
#pragma once

#include <reaction/reaction.h>
#include <reaction/expression/expression_builders.h>

namespace test_reaction {

struct UnaryExpressionSnapshot {
    int initialNegatedSum;
    int updatedNegatedSum;
    bool logicalNotAfterFlip;
    int bitwiseNotValue;
};

/**
 * Function: Demonstrate unary expression builders and operators on reactive values.
 *
 * This function showcases how low-level expression builder helpers (`make_binary_op`,
 * `make_unary_op`) and high-level unary operators (`-`, `!`, `~`) cooperate with the
 * `expr` factory to produce reactive expressions.
 *
 * @param a First input value participating in the sum expression
 * @param b Second input value participating in the sum expression
 * @return UnaryExpressionSnapshot Snapshot of expression outputs before/after updates
 */
inline UnaryExpressionSnapshot test_unary_expression_builders(int a, int b) {
    using namespace reaction;

    // 1. Create reactive variables for a and b using reaction::var
    auto reactive_a = var(a);
    auto reactive_b = var(b);

    // 2. Build negated sum expression using - operator and + operator
    auto sum_expr = reactive_a + reactive_b;
    auto negated_sum = -sum_expr;

    // 3. Create reactive boolean variable for flag
    auto flag_var = var(false);

    // 4. Build logical NOT expression using ! operator
    auto logical_not_expr = !flag_var;

    // 5. Create reactive integer variable for bitwise operations
    auto bitwise_var = var(0b1010); // Example value: 10 in binary

    // 6. Build bitwise NOT expression using ~ operator
    auto bitwise_not_expr = ~bitwise_var;

    // 7. Get initial values using get() method
    int initial_negated_sum = negated_sum.get();
    bool initial_logical_not = logical_not_expr.get();
    int initial_bitwise_not = bitwise_not_expr.get();

    // 8. Update variables to trigger recomputation
    reactive_a.value(a + 1);  // Update a
    reactive_b.value(b + 1);  // Update b
    flag_var.value(true);     // Flip the flag
    bitwise_var.value(0b1100); // Update bitwise value

    // 9. Get updated values using get() method
    int updated_negated_sum = negated_sum.get();
    bool logical_not_after_flip = logical_not_expr.get();
    int final_bitwise_not = bitwise_not_expr.get();

    // 10. Return snapshot struct with all required values
    return UnaryExpressionSnapshot{
        .initialNegatedSum = initial_negated_sum,
        .updatedNegatedSum = updated_negated_sum,
        .logicalNotAfterFlip = logical_not_after_flip,
        .bitwiseNotValue = final_bitwise_not
    };
}

}  // namespace test_reaction
```

