    auto negated = make_unary_expr<NegOp>(sum);

    // 4. Build chained expression using nested reaction::make_binary_expr calls
    auto chained = make_binary_expr<MulOp>(negated, C);

    // 5. Use get() to retrieve initial values
    int initialSum = sum.get();
    int initialNegatedSum = negated.get();
    int initialChainedValue = chained.get();

    // 6. Update variables using value() method
    A.value(a + 1);  // Update A
    C.value(c + 1);  // Update C

    // 7. Use get() to retrieve updated values
    int updatedSum = sum.get();
    int updatedNegatedSum = negated.get();
    int updatedChainedValue = chained.get();

    // 8. Return RawExpressionSnapshot with both sets of values
    return RawExpressionSnapshot{
        .initialSum = initialSum,
        .initialNegatedSum = initialNegatedSum,
        .initialChainedValue = initialChainedValue,
        .updatedSum = updatedSum,
        .updatedNegatedSum = updatedNegatedSum,
